class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    _getParentIndex(i) { return Math.floor((i - 1) / 2); }
    _getLeftChildIndex(i) { return 2 * i + 1; }
    _getRightChildIndex(i) { return 2 * i + 2; }

    _swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    _compare(a, b) {
        // Compare based on distance (the first element)
        return a[0] - b[0];
    }

    enqueue(element) {
        this.heap.push(element);
        this._bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this._sinkDown(0);
        return root;
    }

    _bubbleUp(index) {
        let currentIndex = index;
        while (currentIndex > 0) {
            const parentIndex = this._getParentIndex(currentIndex);
            if (this._compare(this.heap[currentIndex], this.heap[parentIndex]) < 0) {
                this._swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    _sinkDown(index) {
        let currentIndex = index;
        const length = this.heap.length;

        while (true) {
            let leftChildIndex = this._getLeftChildIndex(currentIndex);
            let rightChildIndex = this._getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            // Check left child
            if (leftChildIndex < length && this._compare(this.heap[leftChildIndex], this.heap[smallest]) < 0) {
                smallest = leftChildIndex;
            }

            // Check right child
            if (rightChildIndex < length && this._compare(this.heap[rightChildIndex], this.heap[smallest]) < 0) {
                smallest = rightChildIndex;
            }

            if (smallest !== currentIndex) {
                this._swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }
